package main

import (
	"context"
	"fmt"

	"atena-label/internal/entity"
	"atena-label/internal/repository"
	"atena-label/internal/usecase"
)

// App struct
type App struct {
	ctx            context.Context
	contactUseCase *usecase.ContactUseCase
	groupRepo      repository.GroupRepository
}

// NewApp creates a new App application struct
func NewApp(contactUC *usecase.ContactUseCase, groupRepo repository.GroupRepository) *App {
	return &App{contactUseCase: contactUC, groupRepo: groupRepo}
}

// startup is called when the app starts. The context is saved
// so we can call the runtime methods
func (a *App) startup(ctx context.Context) {
	a.ctx = ctx
}

// GetContacts returns all contacts, optionally filtered by groupID.
func (a *App) GetContacts(groupID string) ([]entity.Contact, error) {
	contacts, err := a.contactUseCase.List(groupID)
	if err != nil {
		return nil, fmt.Errorf("GetContacts: %w", err)
	}
	return contacts, nil
}

// GetContact returns a single contact by ID.
func (a *App) GetContact(id string) (*entity.Contact, error) {
	c, err := a.contactUseCase.Get(id)
	if err != nil {
		return nil, fmt.Errorf("GetContact: %w", err)
	}
	return c, nil
}

// SaveContact creates or updates a contact.
func (a *App) SaveContact(c entity.Contact) (entity.Contact, error) {
	saved, err := a.contactUseCase.Save(c)
	if err != nil {
		return entity.Contact{}, fmt.Errorf("SaveContact: %w", err)
	}
	return saved, nil
}

// DeleteContacts deletes multiple contacts by IDs.
func (a *App) DeleteContacts(ids []string) error {
	for _, id := range ids {
		if err := a.contactUseCase.Delete(id); err != nil {
			return fmt.Errorf("DeleteContacts: %w", err)
		}
	}
	return nil
}

// SearchContacts searches contacts by keyword.
func (a *App) SearchContacts(query string) ([]entity.Contact, error) {
	contacts, err := a.contactUseCase.Search(query)
	if err != nil {
		return nil, fmt.Errorf("SearchContacts: %w", err)
	}
	return contacts, nil
}

// GetGroups returns all groups.
func (a *App) GetGroups() ([]entity.Group, error) {
	groups, err := a.groupRepo.FindAll()
	if err != nil {
		return nil, fmt.Errorf("GetGroups: %w", err)
	}
	return groups, nil
}

package main

import (
	"embed"
	"log"
	"os"
	"path/filepath"

	"github.com/wailsapp/wails/v2"
	"github.com/wailsapp/wails/v2/pkg/options"
	"github.com/wailsapp/wails/v2/pkg/options/assetserver"

	dbpkg "atena-label/internal/infrastructure/sqlite"
	"atena-label/internal/usecase"
)

//go:embed all:frontend/dist
var assets embed.FS

func main() {
	dbPath, err := resolveDBPath()
	if err != nil {
		log.Fatal("DB path:", err)
	}

	db, err := dbpkg.Open(dbPath)
	if err != nil {
		log.Fatal("Open DB:", err)
	}
	defer db.Close()

	contactRepo := dbpkg.NewContactRepo(db)
	contactUC := usecase.NewContactUseCase(contactRepo)
	groupRepo := dbpkg.NewGroupRepo(db)

	app := NewApp(contactUC, groupRepo)

	err = wails.Run(&options.App{
		Title:  "Atena ラベル印刷",
		Width:  1280,
		Height: 800,
		AssetServer: &assetserver.Options{
			Assets: assets,
		},
		BackgroundColour: &options.RGBA{R: 255, G: 255, B: 255, A: 1},
		OnStartup:        app.startup,
		Bind: []interface{}{
			app,
		},
	})

	if err != nil {
		log.Println("Error:", err.Error())
	}
}

func resolveDBPath() (string, error) {
	homeDir, err := os.UserHomeDir()
	if err != nil {
		return "", err
	}
	dir := filepath.Join(homeDir, ".atena-label")
	if err := os.MkdirAll(dir, 0755); err != nil {
		return "", err
	}
	return filepath.Join(dir, "atena.db"), nil
}

import { useState } from 'react'
import { SaveContact } from '../../../wailsjs/go/main/App'
import type { Contact } from '../../types'
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogClose } from '../ui/dialog'

interface Props {
  contact?: Contact  // undefined = 新規作成
  onClose: () => void
  onSaved: () => void
}

const HONORIFICS = ['様', '殿', '御中', '先生']

function emptyContact(): Omit<Contact, 'id' | 'createdAt' | 'updatedAt'> {
  return {
    familyName: '',
    givenName: '',
    familyNameKana: '',
    givenNameKana: '',
    honorific: '様',
    postalCode: '',
    prefecture: '',
    city: '',
    street: '',
    building: '',
    company: '',
    department: '',
    notes: '',
  }
}

export default function ContactEditModal({ contact, onClose, onSaved }: Props) {
  const isNew = !contact
  const [form, setForm] = useState<Omit<Contact, 'id' | 'createdAt' | 'updatedAt'>>(
    contact
      ? {
          familyName: contact.familyName,
          givenName: contact.givenName,
          familyNameKana: contact.familyNameKana,
          givenNameKana: contact.givenNameKana,
          honorific: contact.honorific,
          postalCode: contact.postalCode,
          prefecture: contact.prefecture,
          city: contact.city,
          street: contact.street,
          building: contact.building,
          company: contact.company,
          department: contact.department,
          notes: contact.notes,
        }
      : emptyContact()
  )
  const [errors, setErrors] = useState<Partial<Record<keyof typeof form, string>>>({})
  const [saving, setSaving] = useState(false)
  const [saveError, setSaveError] = useState<string | null>(null)

  const set = (field: keyof typeof form) => (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    setForm((prev) => ({ ...prev, [field]: e.target.value }))
    setErrors((prev) => ({ ...prev, [field]: undefined }))
  }

  const validate = () => {
    const errs: typeof errors = {}
    if (!form.familyName.trim()) errs.familyName = '姓は必須です'
    if (!form.givenName.trim()) errs.givenName = '名は必須です'
    return errs
  }

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    const errs = validate()
    if (Object.keys(errs).length > 0) {
      setErrors(errs)
      return
    }
    setSaving(true)
    setSaveError(null)
    try {
      await SaveContact({
        id: contact?.id ?? '',
        createdAt: contact?.createdAt ?? null,
        updatedAt: contact?.updatedAt ?? null,
        ...form,
      } as Parameters<typeof SaveContact>[0])
      onSaved()
    } catch (err) {
      console.error(err)
      setSaveError(err instanceof Error ? err.message : '保存に失敗しました')
    } finally {
      setSaving(false)
    }
  }

  return (
    <Dialog open onOpenChange={(open) => { if (!open) onClose() }}>
      <DialogContent>
        {/* ヘッダー */}
        <DialogHeader>
          <DialogTitle>
            {isNew ? '連絡先を追加' : '連絡先を編集'}
          </DialogTitle>
          <DialogClose
            onClick={onClose}
            className="text-gray-400 hover:text-gray-600 text-xl leading-none"
          >
            &times;
          </DialogClose>
        </DialogHeader>

        {/* フォーム */}
        <form onSubmit={handleSubmit} className="p-5 space-y-4">
          {/* 氏名 */}
          <div className="grid grid-cols-2 gap-3">
            <Field label="姓" required error={errors.familyName}>
              <input
                type="text"
                value={form.familyName}
                onChange={set('familyName')}
                className={inputCls(!!errors.familyName)}
                placeholder="田中"
              />
            </Field>
            <Field label="名" required error={errors.givenName}>
              <input
                type="text"
                value={form.givenName}
                onChange={set('givenName')}
                className={inputCls(!!errors.givenName)}
                placeholder="太郎"
              />
            </Field>
          </div>

          {/* 氏名かな */}
          <div className="grid grid-cols-2 gap-3">
            <Field label="姓（かな）">
              <input type="text" value={form.familyNameKana} onChange={set('familyNameKana')} className={inputCls()} placeholder="たなか" />
            </Field>
            <Field label="名（かな）">
              <input type="text" value={form.givenNameKana} onChange={set('givenNameKana')} className={inputCls()} placeholder="たろう" />
            </Field>
          </div>

          {/* 敬称 */}
          <Field label="敬称" required>
            <select value={form.honorific} onChange={set('honorific')} className={inputCls()}>
              {HONORIFICS.map((h) => (
                <option key={h} value={h}>{h}</option>
              ))}
            </select>
          </Field>

          {/* 郵便番号 */}
          <Field label="郵便番号">
            <input
              type="text"
              value={form.postalCode}
              onChange={set('postalCode')}
              className={inputCls()}
              placeholder="1000001"
              maxLength={8}
            />
          </Field>

          {/* 都道府県・市区町村 */}
          <div className="grid grid-cols-2 gap-3">
            <Field label="都道府県">
              <input type="text" value={form.prefecture} onChange={set('prefecture')} className={inputCls()} placeholder="東京都" />
            </Field>
            <Field label="市区町村">
              <input type="text" value={form.city} onChange={set('city')} className={inputCls()} placeholder="千代田区" />
            </Field>
          </div>

          {/* 番地 */}
          <Field label="番地">
            <input type="text" value={form.street} onChange={set('street')} className={inputCls()} placeholder="1-1-1" />
          </Field>

          {/* 建物名 */}
          <Field label="建物名">
            <input type="text" value={form.building} onChange={set('building')} className={inputCls()} placeholder="○○ビル 101" />
          </Field>

          {/* 会社名・部署 */}
          <div className="grid grid-cols-2 gap-3">
            <Field label="会社名">
              <input type="text" value={form.company} onChange={set('company')} className={inputCls()} />
            </Field>
            <Field label="部署名">
              <input type="text" value={form.department} onChange={set('department')} className={inputCls()} />
            </Field>
          </div>

          {/* メモ */}
          <Field label="メモ">
            <textarea
              value={form.notes}
              onChange={set('notes')}
              rows={2}
              className={`${inputCls()} resize-none`}
            />
          </Field>

          {/* 保存エラー */}
          {saveError && (
            <p role="alert" className="text-sm text-red-600 bg-red-50 border border-red-200 rounded-md px-3 py-2">
              {saveError}
            </p>
          )}

          {/* ボタン */}
          <div className="flex justify-end gap-2 pt-1">
            <button
              type="button"
              onClick={onClose}
              className="px-4 py-1.5 text-sm text-gray-600 border border-gray-300 rounded-md hover:bg-gray-50"
            >
              キャンセル
            </button>
            <button
              type="submit"
              disabled={saving}
              className="px-4 py-1.5 text-sm bg-blue-600 text-white rounded-md hover:bg-blue-700 disabled:opacity-50"
            >
              {saving ? '保存中...' : '保存'}
            </button>
          </div>
        </form>
      </DialogContent>
    </Dialog>
  )
}

function Field({
  label,
  required,
  error,
  children,
}: {
  label: string
  required?: boolean
  error?: string
  children: React.ReactNode
}) {
  return (
    <div>
      <label className="block text-xs font-medium text-gray-600 mb-1">
        {label}
        {required && <span className="text-red-500 ml-0.5">*</span>}
      </label>
      {children}
      {error && <p className="mt-1 text-xs text-red-500">{error}</p>}
    </div>
  )
}

function inputCls(hasError = false) {
  return `w-full px-2.5 py-1.5 text-sm border rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500 ${
    hasError ? 'border-red-400' : 'border-gray-300'
  }`
}

