const latestDigitsRef = useRef<string>('')

const handlePostalChange = useCallback(async (e: React.ChangeEvent<HTMLInputElement>) => {
  const raw = e.target.value
  setForm((prev) => ({ ...prev, postalCode: raw }))
  setPostalLookupError(null)

  const digits = raw.replace(/\D/g, '')
  latestDigitsRef.current = digits
  if (digits.length !== 7) return

  try {
    const addr = await LookupPostal(digits)
    if (latestDigitsRef.current !== digits) return // 古いリクエストを無視
    setForm((prev) => ({ ...prev, prefecture: addr.prefecture, city: addr.city }))
  } catch {
    if (latestDigitsRef.current === digits) setPostalLookupError('郵便番号が見つかりませんでした')
  }
}, [])
